dark.customCSS:
/* --- APOLLO: ANALOGUE HARDWARE INTERFACE --- */

/* Industrial Chassis Texture */
#sidebar {
	background-image: repeating-linear-gradient(rgba(255,255,255,0.01) 0px, rgba(255,255,255,0.01) 1px, transparent 1px, transparent 2px) !important;
	background-color: #14181f !important;
	border-right: 2px solid #000 !important;
}

/* The Recessed VFD Display */
.prose, textarea, input {
	background-color: #0a0c10 !important;
	border: 2px solid #2a323d !important;
	border-top: 2px solid #000 !important;
	border-left: 2px solid #000 !important;
	border-radius: 4px !important;
	box-shadow: inset 2px 2px 10px rgba(0,0,0,0.8), 1px 1px 0px rgba(255,255,255,0.05) !important;
	font-family: 'JetBrains Mono', monospace !important;
	color: #d1d9e6 !important;
}

/* Backlit Mechanical Switches (Buttons) */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: #2a323d !important;
	border: 1px solid #3f4957 !important;
	border-bottom: 3px solid #000 !important;
	color: #f0f4f7 !important;
	text-transform: uppercase;
	font-weight: 800 !important;
	letter-spacing: 1px;
	border-radius: 4px !important;
	box-shadow: 0 4px 0 #000, 0 8px 10px rgba(0,0,0,0.3);
	transition: all 0.1s ease;
}

button.bg-blue-500:hover {
	background: #3f4957 !important;
	color: #fff !important;
	text-shadow: 0 0 10px rgba(255,255,255,0.5);
}

button.bg-blue-500:active {
	transform: translateY(2px);
	border-bottom: 1px solid #000 !important;
	box-shadow: 0 1px 0 #000, inset 0 2px 5px rgba(0,0,0,0.5) !important;
}

/* Status Indicators */
.chat-item::before {
	content: '';
	display: inline-block;
	width: 6px; height: 6px;
	background: #ff3300;
	border-radius: 50%;
	margin-right: 10px;
	box-shadow: 0 0 5px #ff3300;
}
.chat-item.active::before {
	background: #00ff66;
	box-shadow: 0 0 8px #00ff66;
}

/* Retro Scrollbar */
::-webkit-scrollbar {
	width: 12px;
	background: #0a0c10;
}
::-webkit-scrollbar-thumb {
	background: #2a323d !important;
	border: 3px solid #0a0c10;
	border-radius: 0px;
}

dark.canvasScript:
/**
 * Title: Vector Telemetry
 * Description: Industrial flight path vectors and coordinate pips for the Apollo console.
 */

const CONFIG = {
    pathCount: 8,
    pipCount: 20,
    primaryColor: 'rgba(209, 217, 230, 0.15)',
    accentColor: 'rgba(255, 51, 0, 0.3)',
    speed: 0.002
};

let canvas, ctx, w, h;
let paths = [];
let pips = [];

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
    paths = [];
    for (let i = 0; i < CONFIG.pathCount; i++) {
        paths.push({
            y: Math.random() * h,
            amp: Math.random() * 100 + 50,
            freq: Math.random() * 0.005 + 0.002,
            offset: Math.random() * Math.PI * 2
        });
    }
    pips = [];
    for (let i = 0; i < CONFIG.pipCount; i++) {
        pips.push({
            x: Math.random() * w, y: Math.random() * h,
            vx: (Math.random() - 0.5) * 0.5,
            vy: (Math.random() - 0.5) * 0.5
        });
    }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);

    // Draw Parabolic Vector Paths
    ctx.lineWidth = 1;
    for (let p of paths) {
        ctx.strokeStyle = CONFIG.primaryColor;
        ctx.beginPath();
        for (let x = 0; x < w; x += 10) {
            let y = p.y + Math.sin(x * p.freq + p.offset) * p.amp;
            if (x === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
        }
        ctx.stroke();
        p.offset += CONFIG.speed;
    }

    // Draw Coordinate Pips
    for (let p of pips) {
        p.x += p.vx; p.y += p.vy;
        if (p.x < 0) p.x = w; if (p.x > w) p.x = 0;
        if (p.y < 0) p.y = h; if (p.y > h) p.y = 0;

        ctx.fillStyle = Math.random() > 0.98 ? CONFIG.accentColor : CONFIG.primaryColor;
        ctx.fillRect(p.x, p.y, 2, 2);

        // Subtle labels
        if (Math.random() > 0.999) {
            ctx.font = '8px monospace';
            ctx.fillText(Math.floor(p.x) + ',' + Math.floor(p.y), p.x + 5, p.y);
        }
    }

    requestAnimationFrame(render);
}

